# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Prevent path traversal.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private const string UploadFolder = @"C:\uploads\"; // Update this path as needed

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(UploadFolder, filename);

            if (!Path.IsPathRooted(filePath))
            {
                return NotFound();
            }

            if (System.IO.File.Exists(filePath))
            {
                var mimeType = GetMimeType(filename);
                var fileContent = System.IO.File.ReadAllBytes(filePath);

                return File(fileContent, mimeType);
            }
            else
            {
                return NotFound();
            }
        }

        private string GetMimeType(string filename)
        {
            var extension = Path.GetExtension(filename).ToLower();

            switch (extension)
            {
                case ".pdf":
                    return "application/pdf";
                case ".docx":
                case ".doc":
                    return "application/msword";
                case ".xlsx":
                case ".xls":
                    return "application/vnd.ms-excel";
                case ".pptx":
                case ".ppt":
                    return "application/vnd.ms-powerpoint";
                case ".jpg":
                case ".jpeg":
                case ".png":
                case ".gif":
                case ".bmp":
                    return "image/" + extension.Substring(1);
                default:
                    return "application/octet-stream";
            }
        }
    }
}